diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..6570a591dfc9 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,29 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0), X, 0), C --> fcmp oeq X, C
+      // When X is NaN: fcmp ord is false, select gives 0, 0 == C is false (if C != 0)
+      // When X is ordered: select gives X, X == C
+      // This is equivalent to: X == C (since NaN == C is also false)
+      if (Pred == FCmpInst::FCMP_OEQ && !cast<ConstantFP>(RHSC)->isZero()) {
+        Value *Cond, *TrueVal, *FalseVal;
+        if (match(LHSI, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal)))) {
+          CmpPredicate CmpPred;
+          Value *CmpOp0, *CmpOp1;
+          // Pattern: select (fcmp ord X, 0), X, 0
+          if (match(Cond, m_FCmp(CmpPred, m_Value(CmpOp0), m_Value(CmpOp1))) &&
+              CmpPred == FCmpInst::FCMP_ORD &&
+              TrueVal == CmpOp0 && match(CmpOp1, m_AnyZeroFP()) &&
+              match(FalseVal, m_AnyZeroFP()))
+            return new FCmpInst(Pred, CmpOp0, RHSC, "", &I);
+          // Pattern: select (fcmp ord 0, X), 0, X (commutative fcmp ord)
+          if (match(Cond, m_FCmp(CmpPred, m_Value(CmpOp0), m_Value(CmpOp1))) &&
+              CmpPred == FCmpInst::FCMP_ORD &&
+              TrueVal == CmpOp1 && match(CmpOp0, m_AnyZeroFP()) &&
+              match(FalseVal, m_AnyZeroFP()))
+            return new FCmpInst(Pred, CmpOp1, RHSC, "", &I);
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 439a86d951a8..e261807bbc03 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1729,7 +1729,8 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   if (auto *CI = dyn_cast<FCmpInst>(SI->getCondition())) {
     if (CI->hasOneUse()) {
       Value *Op0 = CI->getOperand(0), *Op1 = CI->getOperand(1);
-      if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1))
+      if (((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1)) &&
+          !CI->isCommutative())
         return nullptr;
     }
   }

